<?php
namespace App\Http\Controllers\Api;use App\Http\Controllers\Controller;use App\Http\Resources\ApiResponse;use App\Http\Resources\CartItemResource;use App\Models\CartItem;use App\Models\Order;use Illuminate\Http\JsonResponse;use Illuminate\Support\Facades\Auth;use Illuminate\Support\Facades\DB;class CartController extends Controller{public function index(): JsonResponse{$items=CartItem::with('product')->where('user_id',Auth::id())->get();return new ApiResponse(CartItemResource::collection($items));}public function store(\App\Http\Requests\CartStoreRequest $request): JsonResponse{$existing=CartItem::where('user_id',Auth::id())->where('product_id',$request->product_id)->first();if($existing){$existing->increment('quantity',$request->quantity??1);return new ApiResponse(new CartItemResource($existing->load('product')),'Cart updated');}$item=CartItem::create(['user_id'=>Auth::id(),'product_id'=>$request->product_id,'quantity'=>$request->quantity??1]);return new ApiResponse(new CartItemResource($item->load('product')),'Added to cart',201);}public function update(\App\Http\Requests\CartUpdateRequest $request,string $id): JsonResponse{$item=CartItem::where('user_id',Auth::id())->findOrFail($id);$item->update(['quantity'=>$request->quantity]);return new ApiResponse(new CartItemResource($item->load('product')));}public function destroy(string $id): JsonResponse{$item=CartItem::where('user_id',Auth::id())->findOrFail($id);$item->delete();return new ApiResponse(null,'Removed from cart');}public function clear(): JsonResponse{Auth::user()->cartItems()->delete();return new ApiResponse(null,'Cart cleared');}public function checkout(\App\Http\Requests\CartCheckoutRequest $request): JsonResponse{return DB::transaction(function()use($request){$cartItems=Auth::user()->cartItems->load('product');if($cartItems->isEmpty()){return new ApiResponse(null,'Cart is empty',422);}$totalAmount=$cartItems->sum(fn($item)=>$item->quantity*$item->product->price);$order=Order::create(['user_id'=>Auth::id(),'total_amount'=>$totalAmount,'delivery_address'=>$request->delivery_address,'cod_amount'=>$request->cod_amount??0,'status'=>'pending',]);foreach($cartItems as $item){$order->items()->create(['product_id'=>$item->product_id,'quantity'=>$item->quantity,'price'=>$item->product->price,]);}Auth::user()->cartItems()->delete();return new ApiResponse(['order'=>new \App\Http\Resources\OrderResource($order->load('items.product'))],'Order created from cart',201);});}}